/* ============================================================
   Alarm State CSS Classes (doc 38 / doc 35)
   Applied to display elements, not theme-dependent.
   ============================================================ */

/* Skeleton loading pulse */
@keyframes io-pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.45;
  }
}

/* Skeleton shimmer ‚Äî module-shaped loading states */
@keyframes io-shimmer {
  0% {
    background-position: 200% 0;
  }
  100% {
    background-position: -200% 0;
  }
}

.io-skeleton {
  background: linear-gradient(
    90deg,
    var(--io-surface-secondary) 25%,
    var(--io-surface-elevated) 50%,
    var(--io-surface-secondary) 75%
  );
  background-size: 200% 100%;
  animation: io-shimmer 1.5s linear infinite;
}

/* Unacknowledged ‚Äî 1Hz flash between alarm color and gray */
@keyframes io-alarm-flash {
  0%,
  49% {
    opacity: 1;
  }
  50%,
  100% {
    opacity: 0.25;
  }
}

.io-unack {
  animation: io-alarm-flash 1s step-end infinite;
}
.io-ack {
  /* Steady alarm color ‚Äî no animation */
}
.io-rtn-unack {
  opacity: 0.6;
}
.io-shelved {
  border-style: dashed !important;
  opacity: 0.7;
}
.io-suppressed {
  opacity: 0.4;
}
.io-oos-display {
  text-decoration: line-through;
  opacity: 0.5;
}

/* Data Quality CSS Classes */
.io-quality-stale {
  outline: 1px dashed var(--io-border-strong);
  opacity: 0.6;
}
.io-quality-bad {
  outline: 1px dashed var(--io-alarm-urgent);
}
.io-quality-comm-fail {
  outline: 1px solid var(--io-alarm-disabled);
  opacity: 0.7;
}
.io-quality-uncertain {
  outline: 1px dotted var(--io-border-strong);
}
.io-quality-manual {
  outline: 1px solid var(--io-alarm-diagnostic);
}

/* ============================================================
   Context Menu Animations
   ============================================================ */

@keyframes io-context-menu-in {
  from {
    opacity: 0;
    transform: scale(0.97) translateY(-3px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

@keyframes io-dropdown-in {
  from {
    opacity: 0;
    transform: scale(0.96) translateY(-4px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

/* ============================================================
   Base resets
   ============================================================ */

* {
  box-sizing: border-box;
}

html,
body,
#root {
  height: 100%;
  margin: 0;
}

body {
  margin: 0;
  background: var(--io-surface-primary);
  color: var(--io-text-primary);
  font-family:
    "InterVariable",
    "Inter",
    -apple-system,
    BlinkMacSystemFont,
    "Segoe UI",
    Roboto,
    "Helvetica Neue",
    sans-serif;
  font-size: var(--io-text-base, 0.875rem);
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* Monospace for code/data contexts */
code,
pre,
kbd,
.io-mono {
  font-family:
    "JetBrains Mono Variable", "JetBrains Mono", "Fira Code", "Courier New",
    monospace;
  font-size: var(--io-text-code, 0.8125rem);
}

/* Tabular numbers for data values ‚Äî prevents layout jitter */
.io-tabular {
  font-variant-numeric: tabular-nums;
}

/* ============================================================
   Scrollbar styling
   ============================================================ */

::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--io-border);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--io-text-muted);
}

/* ============================================================
   Focus ring
   ============================================================ */

:focus-visible {
  outline: 2px solid var(--io-focus-ring, var(--io-accent));
  outline-offset: 2px;
}

/* ============================================================
   Text selection
   ============================================================ */

::selection {
  background: var(--io-accent-subtle);
  color: var(--io-text-primary);
}

/* ============================================================
   Mobile touch targets ‚Äî gloved operation (doc 20 ¬ßTouch Targets)
   60px minimum for standard controls; 72px for critical actions.
   Applies only on coarse-pointer (touch) devices.
   ============================================================ */

@media (pointer: coarse) {
  /* Standard interactive elements ‚Äî 60px minimum */
  button,
  [role="button"],
  a,
  input[type="checkbox"],
  input[type="radio"],
  select,
  .io-tab,
  .io-nav-item,
  .io-list-item {
    min-height: 60px;
    min-width: 60px;
  }

  /* Icon-only buttons expand their hit area via padding */
  button.io-icon-btn {
    min-height: 60px;
    min-width: 60px;
    padding: 12px;
  }

  /* Critical actions (alarm ack, emergency, submit) ‚Äî 72px minimum */
  .io-critical-action,
  button[data-critical="true"],
  [role="button"][data-critical="true"] {
    min-height: 72px;
    min-width: 72px;
  }

  /* Form inputs ‚Äî taller tap zone */
  input[type="text"],
  input[type="number"],
  input[type="email"],
  input[type="password"],
  textarea {
    min-height: 60px;
  }
}

/* ============================================================
   Print stylesheet ‚Äî color normalization (doc 06)
   ============================================================ */

@media print {
  :root {
    --io-surface-primary: #ffffff;
    --io-surface-secondary: #f9fafb;
    --io-surface-elevated: #ffffff;
    --io-surface: #ffffff;
    --io-text-primary: #111827;
    --io-text-secondary: #374151;
    --io-text-muted: #6b7280;
    --io-border: #d1d5db;
    /* Alarm colors preserved (semantic meaning must survive print) */
  }

  body {
    background: #ffffff;
    color: #111827;
  }

  /* Hide navigation chrome */
  .io-sidebar,
  .io-topbar,
  .io-toolbar,
  [role="navigation"] {
    display: none !important;
  }
}

/* Canonical Mode A (view) node selection glow ‚Äî docs/decisions/selection-behavior.md */
[data-node-id].io-node-selected {
  filter: drop-shadow(
      0 0 3px color-mix(in srgb, var(--io-accent) 80%, transparent)
    )
    drop-shadow(0 0 6px color-mix(in srgb, var(--io-accent) 40%, transparent));
}

/* Designer Mode B multi-select: glow on actual shape geometry, not an overlay rect */
svg.io-multiselect-active [data-node-id].io-selected {
  filter: drop-shadow(
      0 0 3px color-mix(in srgb, var(--io-accent) 80%, transparent)
    )
    drop-shadow(0 0 6px color-mix(in srgb, var(--io-accent) 40%, transparent));
}

