 1	/**
 2	 * I/O ThemeContext
 3	 *
 4	 * Provides the active theme name and its associated canvas-compatible color set
 5	 * to all child components. Chart components (uPlot, ECharts) subscribe to this
 6	 * context to get theme colors without reading CSS custom properties.
 7	 *
 8	 * Also provides the active density mode (compact / default / comfortable) so
 9	 * shared components like DataTable can respond to the global setting without
10	 * requiring a caller-supplied prop.
11	 *
12	 * Usage:
13	 *   const colors    = useThemeColors()   // ThemeColorSet for active theme
14	 *   const theme     = useThemeName()     // 'light' | 'dark' | 'hphmi'
15	 *   const setTheme  = useSetTheme()      // call to change active theme
16	 *   const density   = useDensity()       // 'compact' | 'default' | 'comfortable'
17	 *   const setDensity = useSetDensity()   // call to change density
18	 */
19	
20	import React, { createContext, useContext, useState, useCallback } from "react";
21	import type { Theme } from "./tokens";
22	import { initTheme, setTheme as applyThemeTokens } from "./tokens";
23	import { themeColors } from "./theme-colors";
24	import type { ThemeColorSet } from "./theme-colors";
25	
26	// ---------------------------------------------------------------------------
27	// Density type
28	// ---------------------------------------------------------------------------
29	
30	export type Density = "compact" | "default" | "comfortable";
31	
32	const DENSITY_STORAGE_KEY = "io:display:density";
33	
34	function initDensity(): Density {
35	  const stored = localStorage.getItem(DENSITY_STORAGE_KEY);
36	  if (stored === "compact" || stored === "default" || stored === "comfortable")
37	    return stored;
38	  return "default";
39	}
40	
41	// ---------------------------------------------------------------------------
42	// Context shape
43	// ---------------------------------------------------------------------------
44	
45	export interface ThemeContextValue {
46	  /** The active theme name (matches the Theme type in tokens.ts) */
47	  theme: Theme;
48	  /** Canvas-compatible color set for the active theme */
49	  colors: ThemeColorSet;
50	  /** Change the active theme ‚Äî updates CSS tokens AND React state */
51	  setTheme: (theme: Theme) => void;
52	  /** The active density setting */
53	  density: Density;
54	  /** Change the active density ‚Äî updates React state (persisting to localStorage is the caller's responsibility) */
55	  setDensity: (d: Density) => void;
56	}
57	
58	// ---------------------------------------------------------------------------
59	// Helper: map Theme ‚Üí themeColors key
60	// ---------------------------------------------------------------------------

